import { defineHarness } from 'maple-agent-sdk';

export default defineHarness({
  async beforeInvoke(ctx) {
    return { message: ctx.input };
  },
  async onEvent(event, ctx) {
    ctx.log(event.type);
  },
  async afterInvoke(result) {
    return result;
  }
});

import { MapleClient } from './sdk/index.mjs';

const client = new MapleClient({ baseUrl: 'http://127.0.0.1:8787' });
const login = await client.loginLocal({ email: 'dev@example.com' });
const authed = client.withToken(login.token);
const deployments = await authed.listDeployments();
